#!/usr/bin/env python\n\"\"\"  \nEXEMPLOS DE USO - SISTEMA DE PEDIDOS\nDemonstração prática dos dados e funcionalidades\n\"\"\"\n\n# ============================================\n# EXEMPLO 1: Estrutura de Pedido no localStorage\n# ============================================\n\n# Quando um cliente cria um pedido, é salvo assim:\nimport json\nfrom datetime import datetime\n\n# Estrutura de um pedido\npedido_exemplo = {\n    # Identificação\n    \"id\": \"PED123456\",  # ID legível (gerado com PED + timestamp)\n    \"uuid\": \"a1b2c3d4-e5f6-47g8-h9i0-j1k2l3m4n5o6\",  # UUID para sincronização\n    \n    # Cliente\n    \"customer\": {\n        \"id\": \"customer_abc123\",\n        \"name\": \"João Silva\",\n        \"email\": \"joao.silva@gmail.com\",\n        \"phone\": \"(11) 99999-9999\"\n    },\n    \n    # Endereço de Entrega\n    \"shipping\": {\n        \"address\": \"Rua das Flores, 123 - Apt 402\",\n        \"city\": \"São Paulo\",\n        \"state\": \"SP\",\n        \"country\": \"Brasil\"\n    },\n    \n    # Itens do Carrinho\n    \"items\": [\n        {\n            \"id\": \"product_001\",\n            \"name\": \"Camiseta Premium\",\n            \"price\": 89.90,\n            \"quantity\": 2,\n            \"color\": \"Azul Marinho\",\n            \"size\": \"M\",\n            \"subtotal\": 179.80\n        },\n        {\n            \"id\": \"product_002\",\n            \"name\": \"Calça Jeans\",\n            \"price\": 129.90,\n            \"quantity\": 1,\n            \"color\": \"Azul Claro\",\n            \"size\": \"34\",\n            \"subtotal\": 129.90\n        }\n    ],\n    \n    # Totais\n    \"subtotal\": 309.70,\n    \"shipping_cost\": 0.00,\n    \"total\": 309.70,\n    \n    # Status e Rastreio\n    \"status\": \"enviado\",  # pendente_processamento, processando, enviado, entregue, cancelado\n    \"tracking\": {\n        \"code\": \"AA123456789BR\",\n        \"carrier\": \"Correios\",\n        \"url\": \"https://www.correios.com.br/posvales/sro/leiacodigo/AA123456789BR\",\n        \"history\": [\n            {\n                \"status\": \"pendente_processamento\",\n                \"timestamp\": \"2024-01-15T10:00:00Z\",\n                \"message\": \"Pedido recebido\"\n            },\n            {\n                \"status\": \"processando\",\n                \"timestamp\": \"2024-01-15T11:30:00Z\",\n                \"message\": \"Processando pedido\"\n            },\n            {\n                \"status\": \"enviado\",\n                \"timestamp\": \"2024-01-15T15:45:00Z\",\n                \"message\": \"Rastreio Correios adicionado: AA123456789BR\"\n            }\n        ]\n    },\n    \n    # Timestamps\n    \"createdAt\": \"2024-01-15T10:00:00Z\",\n    \"updatedAt\": \"2024-01-15T15:45:00Z\"\n}\n\n# Salvo em localStorage como:\n# localStorage.setItem(\"loja_minimal_orders\", JSON.stringify([pedido_exemplo]))\n\nprint(\"EXEMPLO DE PEDIDO NO SISTEMA:\")\nprint(json.dumps(pedido_exemplo, indent=2, ensure_ascii=False))\n\n\n# ============================================\n# EXEMPLO 2: Estados do Pedido e Transições\n# ============================================\n\nprint(\"\\n\\nESTADOS E TRANSIÇÕES:\")\nprint(\"\"\"\n┌─────────────────────────────────────────────┐\n│     FLUXO DE ESTADOS DO PEDIDO              │\n├─────────────────────────────────────────────┤\n│                                             │\n│  1. ⏳ PENDENTE PROCESSAMENTO                │\n│     ↓ (Admin muda status)                  │\n│                                             │\n│  2. ⚙️  PROCESSANDO                          │\n│     ↓ (Admin adiciona rastreio)            │\n│                                             │\n│  3. 📦 ENVIADO                              │\n│     ↓ (Correios entrega)                   │\n│                                             │\n│  4. ✓ ENTREGUE                             │\n│                                             │\n│  CANCELAR: ✕ em qualquer momento          │\n│                                             │\n└─────────────────────────────────────────────┘\n\"\"\")\n\n\n# ============================================\n# EXEMPLO 3: Validações e Erros\n# ============================================\n\nprint(\"\\nVALIDAÇÕES IMPLEMENTADAS:\")\n\nvalidacoes = {\n    \"Campo Vazio\": {\n        \"teste\": \"Endereço em branco\",\n        \"resultado\": \"❌ Erro: 'Preencha todos os dados de envio.'\",\n        \"status_code\": \"VALIDATION_ERROR\"\n    },\n    \"Carrinho Vazio\": {\n        \"teste\": \"Tentar confirmar sem itens\",\n        \"resultado\": \"❌ Erro: 'Carrinho vazio. Adicione produtos..'\",\n        \"status_code\": \"EMPTY_CART\"\n    },\n    \"Item Incompleto\": {\n        \"teste\": \"Item sem cor ou tamanho\",\n        \"resultado\": \"❌ Erro: 'Dados de produto incompletos.'\",\n        \"status_code\": \"INVALID_ITEM\"\n    },\n    \"Rastreio Inválido\": {\n        \"teste\": \"Código não segue padrão\",\n        \"resultado\": \"❌ Erro: 'Formato inválido. Use: AA000000000BR'\",\n        \"status_code\": \"INVALID_FORMAT\"\n    },\n    \"Tudo Válido\": {\n        \"teste\": \"Todos os campos preenchidos\",\n        \"resultado\": \"✅ Sucesso: 'Pedido confirmado! Número: PED123456'\",\n        \"status_code\": \"SUCCESS\"\n    }\n}\n\nfor tipo, info in validacoes.items():\n    print(f\"\\n{tipo}:\")\n    print(f\"  Teste: {info['teste']}\")\n    print(f\"  Resultado: {info['resultado']}\")\n    print(f\"  Code: {info['status_code']}\")\n\n\n# ============================================\n# EXEMPLO 4: Formatos de Rastreio Válidos/Inválidos\n# ============================================\n\nprint(\"\\n\\nFORMATO DE RASTREIO CORREIOS:\")\nprint(\"\"\"\nPADRÃO VÁLIDO:\n  • 13 caracteres: 2 letras + 9 dígitos + 2 letras\n  • Exemplo: AA123456789BR\n  • Exemplo: BB987654321US\n  • Exemplo: CC555666777DE\n\nEXEMPLOS DE TESTES:\n  ✅ AA123456789BR    → VÁLIDO\n  ✅ AB999888777BR    → VÁLIDO\n  ❌ AA123456789      → INVÁLIDO (falta 2 letras)\n  ❌ A123456789BR     → INVÁLIDO (falta 1 letra)\n  ❌ 12345            → INVÁLIDO (formato errado)\n  ❌ AA123BR          → INVÁLIDO (falta dígitos)\n\"\"\")\n\n\n# ============================================\n# EXEMPLO 5: Sincronização Cliente ↔ Admin\n# ============================================\n\nprint(\"\\n\\nSINCRONIZAÇÃO EM TEMPO REAL:\")\nprint(\"\"\"\nQUANDO UM CLIENTE CRIA UM PEDIDO:\n\n1️⃣  cliente.js executa:\n    └─ Validação completa\n    └─ Cria objeto pedido com estrutura robusta\n    └─ Salva em localStorage(\"loja_minimal_orders\")\n    └─ Dispara Storage Event\n\n2️⃣  Browser dispara Storage Event:\n    └─ key: \"loja_minimal_orders\"\n    └─ newValue: JSON.stringify(orders)\n    └─ url: \"http://localhost:8000/cliente.html\"\n\n3️⃣  admin.js escuta no outro \"aba\":\n    └─ window.addEventListener(\"storage\", ...)\n    └─ Recarrega dados: orders = getStorage(\"loja_minimal_orders\")\n    └─ Renderiza: renderOrders()\n    └─ ✅ Lista de pedidos atualiza AUTOMATICAMENTE\n\nQUANDO ADMIN ATUALIZA RASTREIO:\n\n1️⃣  admin.js executa:\n    └─ Valida código (regex)\n    └─ Gera URL Correios\n    └─ Atualiza status para \"enviado\"\n    └─ Adiciona ao histórico\n    └─ Salva em localStorage\n    └─ Dispara Storage Event\n\n2️⃣  cliente.js escuta:\n    └─ orders atualiza automaticamente\n    └─ ✅ \"Meus Pedidos\" mostra novo status\n    └─ ✅ Cliente vê rastreio sem refresh\n\"\"\")\n\n\n# ============================================\n# EXEMPLO 6: URLs Geradas Automaticamente\n# ============================================\n\nprint(\"\\n\\nGERAÇÃO DE URLS CORREIOS:\")\n\nimport re\n\ndef gerar_url_correios(codigo):\n    \"\"\"Gera URL automática para rastreio nos Correios\"\"\"\n    padrao = r\"^[A-Z]{2}\\d{9}[A-Z]{2}$\"\n    \n    if re.match(padrao, codigo):\n        url = f\"https://www.correios.com.br/posvales/sro/leiacodigo/{codigo}\"\n        return url\n    else:\n        return None\n\n\nexemplos_urls = [\n    \"AA123456789BR\",\n    \"BB987654321US\",\n    \"CC555666777DE\",\n    \"XX999111222FR\",\n]\n\nprint(\"Códigos → URLs geradas automaticamente:\\n\")\nfor codigo in exemplos_urls:\n    url = gerar_url_correios(codigo)\n    print(f\"{codigo} → {url}\")\n\n\n# ============================================\n# EXEMPLO 7: Histórico de Mudanças\n# ============================================\n\nprint(\"\\n\\nHISTÓRICO DE MUDANÇAS DO PEDIDO:\")\nprint(\"\"\"\nCada mudança de status é registrada com:\n  • Status novo\n  • Timestamp exato\n  • Mensagem descritiva\n\nExemplo de histórico completo:\n\n[\n  {\n    \"status\": \"pendente_processamento\",\n    \"timestamp\": \"2024-01-15T10:00:00Z\",\n    \"message\": \"Pedido recebido\"\n  },\n  {\n    \"status\": \"processando\",\n    \"timestamp\": \"2024-01-15T11:30:00Z\",\n    \"message\": \"Status alterado para Processando\"\n  },\n  {\n    \"status\": \"enviado\",\n    \"timestamp\": \"2024-01-15T15:45:00Z\",\n    \"message\": \"Rastreio Correios adicionado: AA123456789BR\"\n  },\n  {\n    \"status\": \"entregue\",\n    \"timestamp\": \"2024-01-20T14:30:00Z\",\n    \"message\": \"Status alterado para Entregue\"\n  }\n]\n\"\"\")\n\n\n# ============================================\n# EXEMPLO 8: Dados Armazenados no localStorage\n# ============================================\n\nprint(\"\\n\\nDESOVEM ARMAZENADAS NO localStorage:\")\nprint(\"\"\"\nTodas as chaves do aplicativo:\n\n1. \"loja_minimal_products\"\n   └─ Array com todos os produtos\n   └─ Cada produto tem: name, price, category, colors[]\n   └─ Cada cor tem: name, hex, image (base64)\n\n2. \"loja_minimal_orders\" ⭐ PRINCIPAL\n   └─ Array com todos os pedidos\n   └─ Estrutura: customer, shipping, items, tracking, status\n   └─ Sincronizado entre cliente e admin\n\n3. \"loja_minimal_customers\"\n   └─ Array com dados dos clientes\n   └─ Cada cliente: id, name, email, phone, cpf\n\n4. \"loja_minimal_cart\"\n   └─ Array com itens no carrinho atual\n   └─ Limpo após confirmar pedido\n\n5. \"loja_minimal_categories\"\n   └─ Array com categorias de produtos\n\n6. \"loja_minimal_currentCustomer\"\n   └─ Objeto do cliente logado\n   └─ Usada para filtrar pedidos do usuario\n\nAcesso via Console do Browser:\n  console.log(JSON.parse(localStorage.getItem(\"loja_minimal_orders\")))\n\"\"\")\n\n\n# ============================================\n# EXEMPLO 9: Código JavaScript das Principais Funções\n# ============================================\n\nprint(\"\\n\\nPRINCIPAIS FUNÇÕES JAVASCRIPT (admin.js):\")\nprint(\"\"\"\n// 1️⃣  Renderizar lista de pedidos\nfunction renderOrders() {\n  orders = getStorage(STORAGE_KEYS.orders, []);\n  const sorted = [...orders].sort((a, b) => \n    new Date(b.createdAt) - new Date(a.createdAt)\n  );\n  // Gera HTML com lista\n}\n\n// 2️⃣  Ver detalhes de um pedido\nfunction showOrderDetail(orderUuid) {\n  const order = orders.find(o => o.uuid === orderUuid);\n  // Mostra modal completo\n}\n\n// 3️⃣  Atualizar status\nfunction updateOrderStatus(orderUuid, newStatus) {\n  const order = orders.find(o => o.uuid === orderUuid);\n  order.status = newStatus;\n  order.tracking.history.push({status, timestamp, message});\n  setStorage(STORAGE_KEYS.orders, orders);\n  // Dispara Storage Event\n}\n\n// 4️⃣  Adicionar rastreio (COM VALIDAÇÃO REGEX)\nfunction addTrackingCode(orderUuid) {\n  const code = document.getElementById(\"tracking-code-input\").value;\n  \n  // Validação: /^[A-Z]{2}\\\\d{9}[A-Z]{2}$/\n  if (!/^[A-Z]{2}\\\\d{9}[A-Z]{2}$/.test(code)) {\n    alert(\"Formato inválido. Use: AA000000000BR\");\n    return;\n  }\n  \n  const order = orders.find(o => o.uuid === orderUuid);\n  order.tracking.code = code;\n  order.tracking.url = \n    `https://www.correios.com.br/posvales/sro/leiacodigo/${code}`;\n  order.status = \"enviado\";\n  order.tracking.history.push({...});\n  setStorage(STORAGE_KEYS.orders, orders);\n  // Dispara Storage Event\n}\n\"\"\")\n\n\n# ============================================\n# EXEMPLO 10: Casos de Teste Importantes\n# ============================================\n\nprint(\"\\n\\nCASOOS DE TESTE CRÍTICOS:\")\nprint(\"\"\"\n1. CRIAR PEDIDO:\n   ✓ Valida endereço, cidade, estado, telefone\n   ✓ Valida itens (cor, tamanho, quantidade)\n   ✓ Gera ID único (PED+timestamp)\n   ✓ Salva em orders\n   ✓ Dispara Storage Event para admin\n\n2. Admin VÊ PEDIDO:\n   ✓ Lista mostra pedido novo\n   ✓ Status correto (⏳ Pendente)\n   ✓ Detalhes completos disponíveis\n\n3. MUDAR STATUS:\n   ✓ Status atualiza no dropdown\n   ✓ Histórico registra mudança\n   ✓ Cliente vê novo status\n\n4. ADICIONAR RASTREIO:\n   ✓ Valida formato (regex)\n   ✓ Gera URL Correios automaticamente\n   ✓ Muda status para \"Enviado\"\n   ✓ Cliente vê rastreio\n   ✓ Link Correios funciona\n\n5. SINCRONIZAÇÃO:\n   ✓ Cliente cria pedido → Admin vê automaticamente\n   ✓ Admin adiciona rastreio → Cliente vê sem refresh\n   ✓ Storage Events disparam corretamente\n   ✓ localStorage sincronizado\n\"\"\")\n\nprint(\"\\n\" + \"=\"*50)\nprint(\"FIM DOS EXEMPLOS\")\nprint(\"=\"*50)\n"